825	// Finalizes the revert process by enabling a special systemd unit prior to
826	// rebooting the node.
827	//
828	// After we write the original factory image to the node, none of the files
829	// specified in the MachineConfig will be written due to how rpm-ostree handles
830	// file writes. Because those files are owned by the layered container image,
831	// they are not present after reboot; even if we were to write them to the node
832	// before rebooting. Consequently, after reverting back to the original image,
833	// the node will lose contact with the control plane and the easiest way to
834	// reestablish contact is to rebootstrap the node.
835	//
836	// By comparison, if we write a file that is _not_ owned by the layered
837	// container image, this file will persist after reboot. So what we do is write
838	// a special systemd unit that will rebootstrap the node upon reboot.
839	// Unfortunately, this will incur a second reboot during the rollback process,
840	// so there is room for improvement here.
841	func (dn *Daemon) finalizeRevertToNonLayering(newConfig *mcfgv1.MachineConfig) (retErr error) {
842		// First, we write the new MachineConfig to a file. This is both the signal
843		// that the revert systemd unit should fire as well as the desired source of
844		// truth.
845		outBytes, err := json.Marshal(newConfig)
846		if err != nil {
847			return fmt.Errorf("could not marshal MachineConfig %q to JSON: %w", newConfig.Name, err)
848		}
849	
850		if err := writeFileAtomicallyWithDefaults(runtimeassets.RevertServiceMachineConfigFile, outBytes); err != nil {
851			return fmt.Errorf("could not write MachineConfig %q to %q: %w", newConfig.Name, runtimeassets.RevertServiceMachineConfigFile, err)
852		}
853	
854		klog.Infof("Wrote MachineConfig %q to %q", newConfig.Name, runtimeassets.RevertServiceMachineConfigFile)
855	
856		defer func() {
857			if retErr != nil {
858				if err := os.RemoveAll(runtimeassets.RevertServiceMachineConfigFile); err != nil {
859					errs := kubeErrs.NewAggregate([]error{err, retErr})
860					retErr = fmt.Errorf("error rolling back %q on disk: %q", runtimeassets.RevertServiceMachineConfigFile, errs)
861					return
862				}
863			}
864		}()
865	
866		// Next, we enable the revert systemd unit. This renders and writes the
867		// machine-config-daemon-revert.service systemd unit, clones it, and writes
868		// it to disk. The reason for doing it this way is because it will persist
869		// after the reboot since it was not written or mutated by the rpm-ostree
870		// process.
871		if err := dn.enableRevertSystemdUnit(newConfig); err != nil {
872			return err
873		}
874	
875		defer func() {
876			if retErr != nil {
877				if err := dn.disableRevertSystemdUnit(); err != nil {
878					errs := kubeErrs.NewAggregate([]error{err, retErr})
879					retErr = fmt.Errorf("error rolling back systemd unit %q on disk: %e", runtimeassets.RevertServiceName, errs)
880					return
881				}
882			}
883		}()
884	
885		return nil
886	}
