1806	// sortNodeList sorts the list of candidate nodes by label topology.kubernetes.io/zone
1807	// nodes without label are at end of list and sorted by age (oldest to youngest)
1808	func sortNodeList(nodes []*corev1.Node) []*corev1.Node {
1809		sort.Slice(nodes, func(i, j int) bool {
1810			iZone, iOk := nodes[i].Labels[zoneLabel]
1811			jZone, jOk := nodes[j].Labels[zoneLabel]
1812	
1813			switch {
1814			case iOk && jOk:
1815				if iZone == jZone {
1816					// if nodes have same labels, sort by creationTime oldest to newest
1817					return nodes[i].GetObjectMeta().GetCreationTimestamp().Time.Before(nodes[j].GetObjectMeta().GetCreationTimestamp().Time)
1818				}
1819				return iZone < jZone
1820			case jOk:
1821				return false
1822			case !iOk && !jOk:
1823				// if nodes have no labels, sort by creationTime oldest to newest
1824				return nodes[i].GetObjectMeta().GetCreationTimestamp().Time.Before(nodes[j].GetObjectMeta().GetCreationTimestamp().Time)
1825			default:
1826				return true
1827			}
1828		})
1829		return nodes
1830	}
