1832	// setUpdateInProgressTaint applies in progress taint to all the nodes that are to be updated.
1833	// The taint on the individual node is removed by MCC once the update of the node is complete.
1834	// This is to ensure that the updated nodes are being preferred to non-updated nodes there by
1835	// reducing the number of reschedules.
1836	func (ctrl *Controller) setUpdateInProgressTaint(ctx context.Context, nodeName string) error {
1837		return clientretry.RetryOnConflict(constants.NodeUpdateBackoff, func() error {
1838			oldNode, err := ctrl.kubeClient.CoreV1().Nodes().Get(ctx, nodeName, metav1.GetOptions{})
1839			if err != nil {
1840				return err
1841			}
1842			oldData, err := json.Marshal(oldNode)
1843			if err != nil {
1844				return err
1845			}
1846	
