2418					} else {
2419						disabledUnits = append(disabledUnits, u.Name)
2420					}
2421				} else {
2422					action := "disable"
2423					if *u.Enabled {
2424						action = "enable"
2425					}
2426					klog.Infof("Could not %s unit %q, because it has no contents, skipping", action, u.Name)
2427				}
2428			} else {
2429				if err := dn.presetUnit(u); err != nil {
2430					// Don't fail here, since a unit may have a dropin referencing a nonexisting actual unit
2431					klog.Infof("Could not reset unit preset for %s, skipping. (Error msg: %v)", u.Name, err)
2432				}
2433			}
2434		}
