21	// syncStatusOnly for MachineConfigNode
22	func (ctrl *Controller) syncStatusOnly(pool *mcfgv1.MachineConfigPool) error {
23		cc, err := ctrl.ccLister.Get(ctrlcommon.ControllerConfigName)
24		if err != nil {
25			return err
26		}
27		nodes, err := ctrl.getNodesForPool(pool)
28		if err != nil {
29			return err
30		}
31	
32		machineConfigStates := []*mcfgv1.MachineConfigNode{}
33		for _, node := range nodes {
34			ms, err := ctrl.client.MachineconfigurationV1().MachineConfigNodes().Get(context.TODO(), node.Name, metav1.GetOptions{})
35			if err != nil {
36				klog.Errorf("Could not find our MachineConfigNode for node. %s: %v", node.Name, err)
37				continue
38			}
39			machineConfigStates = append(machineConfigStates, ms)
40		}
41	
42		// Get fresh copy of MCP from lister to ensure we have the latest status
43		// in case other controllers like build controller updated it recently
44		freshPool, err := ctrl.mcpLister.Get(pool.Name)
45		if err != nil {
46			return fmt.Errorf("could not get fresh MachineConfigPool %q: %w", pool.Name, err)
47		}
48	
49		mosc, mosb, l, err := ctrl.getConfigAndBuildAndLayeredStatus(freshPool)
50		if err != nil {
51			return fmt.Errorf("could get MachineOSConfig or MachineOSBuild: %w", err)
52		}
53	
54		newStatus := ctrl.calculateStatus(machineConfigStates, cc, freshPool, nodes, mosc, mosb)
55		if equality.Semantic.DeepEqual(freshPool.Status, newStatus) {
56			return nil
57		}
58	
59		newPool := freshPool.DeepCopy()
60		newPool.Status = newStatus
61		_, err = ctrl.client.MachineconfigurationV1().MachineConfigPools().UpdateStatus(context.TODO(), newPool, metav1.UpdateOptions{})
62		if err != nil {
63			return fmt.Errorf("could not update MachineConfigPool %q: %w", newPool.Name, err)
64		}
65	
66		if pool.Spec.Configuration.Name != newPool.Spec.Configuration.Name {
67			ctrl.eventRecorder.Eventf(pool, corev1.EventTypeNormal, "Updating", "Pool %s now targeting %s", pool.Name, getPoolUpdateLine(newPool, mosc, l))
68		}
69		if pool.Status.Configuration.Name != newPool.Status.Configuration.Name {
70			ctrl.eventRecorder.Eventf(pool, corev1.EventTypeNormal, "Completed", "Pool %s has completed update to %s", pool.Name, getPoolUpdateLine(newPool, mosc, l))
71		}
72		return err
73	}
